mapper.select:
SELECT p.PLACE_ID as placeId, p.PLACE_NAME as name, p.IMAGE_URL as imageUrl, p.ADDRESS as region, a.ACCOMMODATION_TYPE as accommodationType, MIN(r.AMOUNT + (GREATEST(0, (#{adult} + #{child}) - r.ROOMBASECOUNT) * 20000)) as minPrice FROM PLACE p JOIN ACCOMMODATION a ON p.PLACE_ID = a.PLACE_ID JOIN ROOM r ON a.PLACE_ID = r.PLACE_ID JOIN ACCOMMODATION_FACILITY af ON a.AF_ID = af.AF_ID JOIN ROOM_FACILITY rf ON r.RF_ID = rf.RF_ID WHERE 1=1
AND NOT EXISTS ( SELECT 1 FROM RESERVATION res WHERE res.ROOM_ID = r.ROOM_ID AND res.STATUS = 'SUCCESS' -- 취소된 예약은 무시하고 성공한 예약만 겹치는지 체크 AND res.CHECK_IN_DATE < TO_DATE(#{checkout}, 'YYYY-MM-DD') AND res.CHECK_OUT_DATE > TO_DATE(#{checkin}, 'YYYY-MM-DD') )
AND p.ADDRESS LIKE '%' || #{region} || '%'
AND a.ACCOMMODATION_TYPE IN
#{type}
AND r.AMOUNT >= #{minPrice}
AND r.AMOUNT <= #{maxPrice}
AND r.MAX_CAPACITY >= (#{adult} + #{child})
AND af.FITNESS = 1 AND af.CHKCOOKING = 1 AND af.BARBECUE = 1 AND af.BEVERAGE = 1 AND af.KARAOKE = 1 AND af.PUBLICPC = 1 AND af.SAUNA = 1
GROUP BY p.PLACE_ID, p.PLACE_NAME, p.IMAGE_URL, p.ADDRESS, a.ACCOMMODATION_TYPE

SELECT IMAGE_URL 
FROM ACCOMMODATION_IMAGE 
WHERE PLACE_ID = #{placeId}

mapper.update:
UPDATE ROOM_LOCK 
SET EXPIRE_AT = SYSDATE + (5/(24*60))
WHERE ROOM_ID = #{roomId} AND CHECKIN_DATE = #{checkin}

mapper.insert:
INSERT INTO ORDER_DETAIL (
    DETAIL_ID, ORDER_ID, RESERVATION_ID, AMOUNT, STATUS
) VALUES (
    ORDER_DETAIL_SEQ.NEXTVAL, #{merchantUid}, #{reservationId}, #{amount}, 'SUCCESS'
)

INSERT INTO PAYMENT (
    PAYMENT_ID, ORDER_ID, PG_PROVIDER, PG_TID, AMOUNT, STATUS, PAID_AT
) VALUES (
    PAYMENT_SEQ.NEXTVAL, #{merchantUid}, #{payMethod}, #{impUid}, #{amount}, 'SUCCESS', SYSDATE
)
